'use strict';

const fs = require('fs');

const dxf = require('./lib/');

export default (filePathArr, savePathArr, callback, code) => {
    const parsed = dxf.parseString(fs.readFileSync(filePathArr, code || 'utf-8'));
    const svg = dxf.toSVG(parsed);
    fs.writeFileSync(savePathArr, svg, code || 'utf-8');
    if (callback) callback();
}
